//==============================================================================
// Init_Peripherals
//==============================================================================
static void Init_Peripherals(void) {
	SystemCoreClockUpdate();
	retarget_init();
	
	// Save the SFRPAGE
	uint8_t SFRPAGE_save = SFRPAGE;

	//Init Watchdog
	PCA0_Init();

	//Init clocks
	// Init_Clocks();

	//Init ports
	// Init_Ports(); // TODO: Check on schematic

	//Init all used timers
	Init_Timers();

	//Init SMBus (I2C slave and master)
	Init_SMBus();

	//Init interrupts
	Init_Interrupts();

	//Start precision temperature sensor
	Start_temperature_sensor();

	// Restore the SFRPAGE
	SFRPAGE = SFRPAGE_save;
}

