//================================================================================
//Init clocking system
// This function initializes the system clock to use the internal HF oscillator at 49.0 MHz.
static void Init_Clocks(void) {
	// ”????????? ??????? ??????????? (????????????????) ?????????? = 49.0 ?v?
	OSCICN = 0x80;		// Enable HF oscillator

	PFE0CN    |= 0x20;		// Enable Prefetch Engine
	FLSCL     |= 0x10;		// Flash Read Timing: SYSCLK <= 50 MHz

	CLKSEL = 0x03;		// clock source is HF oscillator (without divider)

}
