//================================================================================
// Init Port IO pins
static void Init_Ports(void) {
	// ----- Port 0
	//P0.0 .. P0.3 - reserved
	//P0.1 - test pin (output)
	// - P0.4, P0.5 pins are used for SMBus0 (I2C slave)
	// - P0.6, P0.7 pins are used for SMBus1 (I2C master)
	P0MDIN = 0xFF;	//All pins are digital
	P0MDOUT = P0MDOUT_B1__PUSH_PULL;	//All pins are open-drain, except Test_pin
	P0SKIP = 0x0F;		//skip 0..3 pins
	P0MASK = 0x00;		//all pins are ignored by Match

	// ----- Port 1
	// - P1.0, P1.1 pins are used as M-RS0 and M-RS1 (outputs to CDR chip)
	// - P1.2 - reserved
	// - P1.3 - TX_FAULT (input from CDR)
	// - P1.4 - TX_DISABLE (input from ext. connector)
	// - P1.5 - LOS (input from CDR)
	// - P1.6, P1.7 pins are used as RS0 and RS1 (inputs from ext. connector)
	P1MDIN = 0xFF;	//All pins are digital
	P1MDOUT = 0x00;	//All pins are open-drain
	P1SKIP = 0x00;

	// ----- Port 2
	//not used

	//SMBus 0 I/O routed to Port pins, all other peripherals are not used
	XBR0 = XBR0_SMB1E__ENABLED | XBR0_SMB0E__ENABLED;	// Enable the SMBus0 & SMBus1 on the XBAR

	XBR1 = XBR1_XBARE__ENABLED;                        // Enable the XBAR and weak pull-ups

}
