//================================================================================
// TIMER_SETUP_0_enter_DefaultMode_from_RESET
static void Init_Timers(void) {
	TMR0->CTRL_bit.INTEN = 0;
	
	TMR1->CTRL_bit.INTEN = 1;
	TMR1->CTRL_bit.ON = 1;
	
	uint32_t Temp_u32;
	SFRPAGE = 0x00;
	// SCA (Timer 0/1 Prescale) = SYSCLK_DIV_4 (System clock divided by 4.)
	// Timer 0 and Timer 1 use prescaled clock (SCA)
	// Timers 2 and 3 (H and L) use appropriate TnXCLK
	CKCON = CKCON_SCA__SYSCLK_DIV_4 | CKCON_T0M__PRESCALE | CKCON_T1M__PRESCALE
			| CKCON_T2MH__EXTERNAL_CLOCK | CKCON_T2ML__EXTERNAL_CLOCK
			| CKCON_T3MH__EXTERNAL_CLOCK | CKCON_T3ML__EXTERNAL_CLOCK;

	// CKCON1 - T4 use appropriate TnXCLK, T5 use appropriate SYSCLK
	CKCON1 = CKCON1_T4MH__EXTERNAL_CLOCK | CKCON1_T4ML__EXTERNAL_CLOCK
			| CKCON1_T5MH__SYSCLK | CKCON1_T5ML__SYSCLK;

	// Timer 0 use Mode 1 (16-bit Counter/Timer)
	// Timer 1 use Mode 2 (8-bit Counter/Timer with Auto-Reload)
	// T0 and T1 used as timers w/o GATE
	TMOD = TMOD_T0M__MODE1 | TMOD_T1M__MODE2 | TMOD_CT0__TIMER
			| TMOD_GATE0__DISABLED | TMOD_CT1__TIMER | TMOD_GATE1__DISABLED;

	// Timers 0 and 1 clocked by SYSCLK/4
	//------- Timer0

	//------- Timer1
	// Timer1 is used for SMBus0 clock source
	// and timer overflow freq = SMB freq * 3
	Temp_u32 = (SYSCLK_FREQ / 4) / (SMB_FREQ * 3);
	Temp_u32 = (256 - Temp_u32) & 0xFF;
	TH1 = Temp_u32;
	TL1 = Temp_u32;
    TCON_TR1 = 1;                         // Start Timer1
	//-----

	//------- Timer2
	// Timer2 is used to generate 10 ms periodic interrupt
	// Timer2 use SYSCLK / 12, 16-bit reload mode, don't start yet
	TMR2CN = 0x00;
	//We need to count 10ms (100 Hz)
	Temp_u32 = (65536 - ((SYSCLK_FREQ / 12) / 100)) & 0xFFFF;
	TMR2RLH = (Temp_u32 >> 8) & 0xFF;
	TMR2RLL = Temp_u32 & 0xFF;
	TMR2CN_TR2 = 1;                         // Start Timer2
	//-----

	//------- Timer3
	//-----

	//------- Timer4
	//-----

	//------- Timer5
	// Timer5 is clocked by sysclk and used for SMBus1 clock source
	// and timer overflow freq = SMB freq * 3
	SFRPAGE = TIMER5_PAGE;
	Temp_u32 = (SYSCLK_FREQ) / (SMB_FREQ * 3);
	Temp_u32 = (65536 - Temp_u32) & 0xFFFF;
	TMR5RLH = (Temp_u32 >> 8) & 0xFF;
	TMR5RLL = Temp_u32 & 0xFF;
	TMR5CN = TMR5CN_TR5__RUN;	//Start timer5 in 16-bit auto-reload mode
	SFRPAGE = 0;
	//-----
}
