//================================================================================
// Init SMBus0 (I2C slave) and SMBus1 (I2C master)
static void Init_SMBus(void) {

//	SMBTC = 0x00;	//default values (no SMBus pin swapping)
	SMBTC = SMBTC_SMB1SWAP__SDA_HIGH_PIN;	//default values (no SMBus pin swapping)


	//SMBus0
	SFRPAGE = 0x00;
	// Use Timer1 overflows as SMBus clock source; Enable slave mode;
	// Enable setup & hold time extensions; Enable SMBus Free timeout detect;
	// Disable SCL low timeout detect;
	SMB0CF	= SMB0CF_SMBCS__TIMER1 | SMB0CF_SMBFTE__FREE_TO_ENABLED |
			SMB0CF_SMBTOE__SCL_TO_DISABLED | SMB0CF_EXTHOLD__ENABLED |
			SMB0CF_INH__SLAVE_ENABLED;
	SMB0ADM	= 0xFE;		// Disable HW address acknowlendge
	SMB0CF |= SMB0CF_ENSMB__ENABLED;		// Enable SMBus0;

	//SMBus1
	SFRPAGE = SMBUS1_PAGE;
	// Use Timer5 overflows as SMBus clock source; Master mode (Disable slave mode);
	// Enable setup & hold time extensions; Enable SMBus Free timeout detect;
	// Disable SCL low timeout detect;
	SMB1CF	= SMB1CF_SMBCS__TIMER5 | SMB1CF_SMBFTE__FREE_TO_ENABLED |
			SMB1CF_SMBTOE__SCL_TO_DISABLED | SMB1CF_EXTHOLD__ENABLED |
			SMB1CF_INH__SLAVE_DISABLED;
	//For master ADR and ADM registers are not used
	SMB1CF |= SMB1CF_ENSMB__ENABLED;		// Enable SMBus1;
	SFRPAGE = 0;

}
