//================================================================================
static void Init_Interrupts(void) {
	SFRPAGE = 0x00;
	// EIE1 - Extended Interrupt Enable 1
	// Enable SMB0 (I2C slave) interrupts
	// Disable Timer3, ADC0, Match, CP0, CP1, PCA0 interrupts
	EIE1 = EIE1_EADC0__DISABLED | EIE1_EWADC0__DISABLED | EIE1_ECP0__DISABLED
			| EIE1_EMAT__DISABLED | EIE1_EPCA0__DISABLED
			| EIE1_ESMB0__ENABLED | EIE1_ET3__DISABLED;
//	| EIE1_ESMB0__DISABLED | EIE1_ET3__DISABLED;

	// EIE2 - Extended Interrupt Enable 2
	// Disable SMB1 (I2C master) interrupt (SMB1 works in this project without interrupt)
	// PTS, Timer4, Timer5 interrupts
	EIE2 = EIE2_EPTS__DISABLED | EIE2_ET4__DISABLED
			| EIE2_ET5__DISABLED | EIE2_ESMB1__DISABLED;
//			| EIE2_ET5__DISABLED | EIE2_ESMB1__ENABLED;

	// All int priority registers uses default values

	// IE
	// Enable each interrupt according to its individual mask setting
	// Enable Timer2 interrupt
	// Disable ExtInt0, ExtInt1, SPI0, Timer0, Timer1, UART0 interrupts
	IE = IE_EA__ENABLED | IE_EX0__DISABLED | IE_EX1__DISABLED
			| IE_ESPI0__DISABLED | IE_ET0__DISABLED | IE_ET1__DISABLED
			| IE_ET2__ENABLED | IE_ES0__DISABLED;

}
//================================================================================

//================================================================================
static void Start_temperature_sensor(void) {
	//Start new measurement
	SFRPAGE = PTEMPCFG_PAGE;
	TS0CN = TS0CN_TSSTRT__START1;
	TS0CN = TS0CN_TSSTRT__START2;

	SFRPAGE = 0x00;	//restore default page
}
//================================================================================

//================================================================================
//Read measurement if data is ready and start new measurement
static void Read_temperature_sensor(void) {
	//Check data ready flag
	SFRPAGE = PTEMPCFG_PAGE;
	if(TS0CN & TS0CN_TSDN__SET) {
		//Data is ready -> read result
		SFRPAGE = PTEMPDAT_PAGE;
		Temp_u16 = (TS0DATH << 8) | TS0DATL;
		A2Up_Page.var.CPU_Temp = Temp_u16;

		//Start new measurement
		SFRPAGE = PTEMPCFG_PAGE;
		TS0CN = TS0CN_TSSTRT__START1;
		TS0CN = TS0CN_TSSTRT__START2;
	}
	SFRPAGE = 0x00;	//restore default page
}
